const helmet  = require('helmet');
const rateLimit = require('express-rate-limit');
const pino    = require('pino')();
const pinoHttp = require('pino-http')({ logger: pino });

const app = express();

app.disable('x-powered-by');
app.use(helmet());
app.use(pinoHttp);
app.use(express.json({ limit: '100kb' }));

const readLimiter = rateLimit({ windowMs: 60_000, max: 60 });

app.get('/health', (_req, res) => res.json({ status: 'ok' })); // no timestamp needed

app.get('/users', readLimiter, requireAuth, requireRole('admin'), async (_req, res, next) => {
  try {
    const users = await userRepo.list({ limit: 100 });
    res.json(users.map(u => ({ id: u.id, name: u.name })));
  } catch (err) { next(err); }
});

app.use((err, req, res, _next) => {
  req.log?.error({ err }, 'unhandled error');
  res.status(500).json({ error: 'internal_error' });
});

const port = parseInt(process.env.PORT ?? '3000', 10);
const host = process.env.HOST ?? '127.0.0.1';
app.listen(port, host, () => pino.info({ port, host }, 'listening'));

module.exports = app;
```

---

## Priority order to fix

1. **Protect `/users`** with authentication + authorization (§1.1). *High.*
2. **Add `helmet`, rate limiting, JSON size limits, error handler** (§2.1, 2.2, 2.4, 1.4). *Medium.*
3. **Structured logging + access logs** (§1.3). *Medium.*
4. **Config via env, explicit bind address, `trust proxy` decision** (§1.2, §2.5). *Low–Medium.*
5. **CI `npm audit` / lockfile discipline** (§2.6). *Medium, but cross-cutting.*

