const allowed = (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean);
app.use(cors({
  origin: (origin, cb) => (!origin || allowed.includes(origin))
    ? cb(null, true)
    : cb(new Error('origin_not_allowed')),
  credentials: true,
  methods: ['GET', 'POST'],
  maxAge: 600,
}));
```

Never use `origin: '*'` together with `credentials: true`.

