const port = Number(process.env.PORT) || 3000;
app.set('trust proxy', 1); // if behind one LB hop
app.listen(port, host, () => logger.info({ host, port }, 'listening'));
```

---

## 9. Config from literals (A05) — **Low**

Port, ports, and any future secrets should come from environment and be validated at startup (fail fast):

```js
const { z } = require('zod');
const Env = z.object({
  PORT: z.coerce.number().int().min(1).max(65535).default(3000),
  JWT_PUBLIC_KEY: z.string().min(1),
  JWT_ISSUER: z.string().url(),
  JWT_AUDIENCE: z.string().min(1),
  ALLOWED_ORIGINS: z.string().default(''),
});
const env = Env.parse(process.env);
```

---

## 10. Hardcoded user data (A08 — Software & Data Integrity) — **Low (contextual)**

The inline array is clearly a placeholder. When you wire a real data source, use parameterized queries / an ORM with bound parameters to avoid SQL/NoSQL injection:

```js
// pg example — parameterized, never string-concatenate
const { rows } = await pool.query(
