app.disable('x-powered-by');            // Remove fingerprinting header
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      objectSrc: ["'none'"],
      frameAncestors: ["'none'"],
    },
  },
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true },
  referrerPolicy: { policy: 'no-referrer' },
}));
```

---

### 2. `/users` endpoint: unauthenticated PII exposure (High — A01)

`GET /users` returns names and email addresses to any unauthenticated caller. Email addresses are PII; this violates access control and likely GDPR/data-minimization expectations.

**Fix — require auth + minimize the response:**

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const token = header.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) return res.status(401).json({ error: 'unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_PUBLIC_KEY, { algorithms: ['RS256'] });
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

app.get('/users', requireAuth, (req, res) => {
  // Return minimum data; do not leak emails unless the caller is authorized
  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];
  res.json(users);
});
```

