**Recommendation:** require auth and, ideally, scope results to the caller.

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const token = header.startsWith('Bearer ') ? header.slice(7) : null;
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET, { algorithms: ['HS256'] });
    next();
  } catch {
    return res.status(401).json({ error: 'Unauthorized' });
  }
}

app.get('/users', requireAuth, requireRole('admin'), (req, res) => { /* ... */ });
```

### 2. Sensitive Data Exposure — OWASP A02 (Medium)

Even with auth added, the endpoint returns raw email addresses. Emails are PII under GDPR/CCPA. Return the minimum fields needed and mask where appropriate. Ensure the process is behind TLS (HTTPS) — `app.listen(3000)` serves cleartext HTTP.

```js
// Prefer serving behind a TLS-terminating proxy (ALB/nginx),
// and return only fields the caller is entitled to see.
res.json(users.map(u => ({ id: u.id, name: u.name })));
