### 1. `/users` has no authentication or authorization (High — A01)

```js
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

Anyone who can reach the service can enumerate users and harvest email addresses (useful for phishing, credential stuffing, GDPR violations).

**Recommendation:** add an auth middleware and gate the route.

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const header = req.headers.authorization || '';
  const [scheme, token] = header.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return res.status(401).json({ error: 'unauthorized' });
  }
  try {
    req.user = jwt.verify(token, process.env.JWT_PUBLIC_KEY, {
      algorithms: ['RS256'],      // pin the algorithm — never allow "none" or HS*
      issuer: process.env.JWT_ISSUER,
      audience: process.env.JWT_AUDIENCE,
    });
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

app.get('/users', requireAuth, (req, res) => { /* ... */ });
```

Also consider: do callers need `email` at all? Return the minimum viable payload.

---

### 2. No TLS / HTTPS (High — A02)

`app.listen(3000, ...)` serves plain HTTP, so credentials/tokens/PII travel in cleartext on the wire.

**Recommendation:** terminate TLS at the load balancer / ingress (ALB, Nginx, Envoy) and enforce HSTS via `helmet`. If this process must terminate TLS directly, use `https.createServer` with a proper cert:

```js
const https = require('https');
const fs = require('fs');

https
  .createServer(
    {
      key: fs.readFileSync(process.env.TLS_KEY_PATH),
      cert: fs.readFileSync(process.env.TLS_CERT_PATH),
      minVersion: 'TLSv1.2',
    },
    app,
  )
  .listen(process.env.PORT || 3000);
```

---

### 3. Missing security headers (Medium — A05)

No `X-Content-Type-Options`, `Strict-Transport-Security`, `Content-Security-Policy`, `X-Frame-Options`, etc.

**Recommendation:** use `helmet`.

```js
const helmet = require('helmet');

app.disable('x-powered-by');              // don't advertise Express
app.use(helmet({
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true },
  contentSecurityPolicy: { /* tune for your surface */ },
  referrerPolicy: { policy: 'no-referrer' },
}));
```

---

### 4. No rate limiting (Medium — A05 / DoS)

`/users` can be scraped or fuzzed without limits.

**Recommendation:**

```js
const rateLimit = require('express-rate-limit');

app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));
```

For auth-sensitive endpoints, use a stricter bucket (e.g. 10/min per IP + user).

---

### 5. CORS not configured (Medium — A05)

Today there is no CORS, so browsers will block cross-origin calls — which is safe by default. But as soon as a frontend is added, engineers often reach for `app.use(cors())` with no options, which defaults to `Access-Control-Allow-Origin: *`. Pre-empt this:

```js
const cors = require('cors');

app.use(cors({
  origin: (origin, cb) => {
    const allowed = (process.env.ALLOWED_ORIGINS || '').split(',');
    cb(null, !origin || allowed.includes(origin));
  },
  credentials: true,
  methods: ['GET', 'POST'],
}));
```

Never echo `req.headers.origin` back unconditionally — that's effectively wildcard CORS with credentials.

---

