  const header = req.headers.authorization || '';
  const [scheme, token] = header.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return res.status(401).json({ error: 'unauthorized' });
  }
  try {
    req.user = jwt.verify(token, process.env.JWT_PUBLIC_KEY, {
      algorithms: ['RS256'],      // pin the algorithm — never allow "none" or HS*
      issuer: process.env.JWT_ISSUER,
      audience: process.env.JWT_AUDIENCE,
    });
    next();
  } catch {
    return res.status(401).json({ error: 'unauthorized' });
  }
}

app.get('/users', requireAuth, (req, res) => { /* ... */ });
```

Also consider: do callers need `email` at all? Return the minimum viable payload.

---

### 2. No TLS / HTTPS (High — A02)

`app.listen(3000, ...)` serves plain HTTP, so credentials/tokens/PII travel in cleartext on the wire.

**Recommendation:** terminate TLS at the load balancer / ingress (ALB, Nginx, Envoy) and enforce HSTS via `helmet`. If this process must terminate TLS directly, use `https.createServer` with a proper cert:

```js
const https = require('https');
const fs = require('fs');

https
  .createServer(
    {
      key: fs.readFileSync(process.env.TLS_KEY_PATH),
      cert: fs.readFileSync(process.env.TLS_CERT_PATH),
      minVersion: 'TLSv1.2',
    },
    app,
  )
  .listen(process.env.PORT || 3000);
```

---

### 3. Missing security headers (Medium — A05)

No `X-Content-Type-Options`, `Strict-Transport-Security`, `Content-Security-Policy`, `X-Frame-Options`, etc.

**Recommendation:** use `helmet`.

```js
const helmet = require('helmet');

app.disable('x-powered-by');              // don't advertise Express
app.use(helmet({
  hsts: { maxAge: 31536000, includeSubDomains: true, preload: true },
  contentSecurityPolicy: { /* tune for your surface */ },
  referrerPolicy: { policy: 'no-referrer' },
}));
```

---

### 4. No rate limiting (Medium — A05 / DoS)

`/users` can be scraped or fuzzed without limits.

**Recommendation:**

```js
const rateLimit = require('express-rate-limit');

app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));
```

For auth-sensitive endpoints, use a stricter bucket (e.g. 10/min per IP + user).

---

### 5. CORS not configured (Medium — A05)

Today there is no CORS, so browsers will block cross-origin calls — which is safe by default. But as soon as a frontend is added, engineers often reach for `app.use(cors())` with no options, which defaults to `Access-Control-Allow-Origin: *`. Pre-empt this:

```js
const cors = require('cors');

app.use(cors({
  origin: (origin, cb) => {
    const allowed = (process.env.ALLOWED_ORIGINS || '').split(',');
    cb(null, !origin || allowed.includes(origin));
  },
  credentials: true,
  methods: ['GET', 'POST'],
}));
```

Never echo `req.headers.origin` back unconditionally — that's effectively wildcard CORS with credentials.

---

### 6. No structured logging or request correlation (Medium — A09)

Only `console.log` on startup. You cannot detect abuse, auditing is impossible, and incident response is crippled.

**Recommendation:** add `pino-http` (or `morgan` at a minimum) and redact sensitive fields.

```js
const pinoHttp = require('pino-http');

app.use(pinoHttp({
  redact: ['req.headers.authorization', 'req.headers.cookie'],
  customProps: (req) => ({ requestId: req.id }),
}));
```

---

### 7. No global error handler (Medium — A04)

An unhandled exception in a handler will bubble to Express's default error handler, which **includes the stack trace in the response body when `NODE_ENV !== 'production'`**. That is an information-disclosure risk if the service is ever deployed without `NODE_ENV=production`.

**Recommendation:** add a terminal error middleware (must be the *last* middleware):

```js
// 404
app.use((req, res) => res.status(404).json({ error: 'not_found' }));

// 500 — never leak internals
app.use((err, req, res, next) => {
  req.log?.error({ err }, 'unhandled error');
  res.status(err.status || 500).json({ error: 'internal_error' });
});
```

Also handle process-level crashes:

```js
process.on('unhandledRejection', (err) => { /* log + exit */ });
process.on('uncaughtException',  (err) => { /* log + exit */ });
```

---

### 8. Hardcoded port (Low — A05)

```js
app.listen(3000, ...);
```

Port should come from `process.env.PORT` so that container orchestrators can choose.

```js
const port = Number(process.env.PORT) || 3000;
app.listen(port, () => console.log(`listening on ${port}`));
```

---

### 9. Side-effect on `require()` (Low)

```js
app.listen(3000, ...);
module.exports = app;
```

Importing this module for tests also starts a real TCP listener — tests become flaky and may leak handles. Split the concerns:

```js
// app.js — exports the configured Express app only
module.exports = app;

// server.js — the only place that binds
const app = require('./app');
const server = app.listen(process.env.PORT || 3000);

function shutdown() {
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref();
}
process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
```

This also gives you a **graceful shutdown**, which matters for Kubernetes rolling deploys.

---

### 10. Pre-emptive injection / body-parser hardening (Low — A03)

No `express.json()` is configured today, so no JSON is accepted. The moment one is added, set limits and reject unexpected types:

```js
app.use(express.json({ limit: '100kb', strict: true }));
app.use(express.urlencoded({ extended: false, limit: '100kb' }));
```

For any future route that takes input (e.g. `/users/:id`), validate with a schema library:

```js
const { z } = require('zod');

const idSchema = z.coerce.number().int().positive();

app.get('/users/:id', requireAuth, (req, res) => {
  const parsed = idSchema.safeParse(req.params.id);
  if (!parsed.success) return res.status(400).json({ error: 'bad_id' });
  // use parsed.data, not req.params.id, in downstream queries
});
```

Always use **parameterised queries / ORMs** — never string-concatenate SQL with `req.*` values.

---

