```js
const express  = require('express');
const helmet   = require('helmet');
const cors     = require('cors');
const rateLimit = require('express-rate-limit');
const pinoHttp  = require('pino-http');

const app = express();

app.disable('x-powered-by');
app.set('trust proxy', 1);                // if behind an LB/ingress

app.use(helmet({ hsts: { maxAge: 31536000, includeSubDomains: true, preload: true } }));
app.use(cors({ origin: (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean) }));
app.use(express.json({ limit: '100kb', strict: true }));
app.use(pinoHttp({ redact: ['req.headers.authorization', 'req.headers.cookie'] }));
app.use(rateLimit({ windowMs: 60_000, max: 100, standardHeaders: true, legacyHeaders: false }));

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (req, res) => {
  // TODO: fetch from a data store; return the minimum fields needed.
  res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
});

app.use((req, res) => res.status(404).json({ error: 'not_found' }));
app.use((err, req, res, _next) => {
  req.log?.error({ err }, 'unhandled error');
  res.status(err.status || 500).json({ error: 'internal_error' });
});

module.exports = app;     // bind in a separate server.js
```

---

## What I did *not* flag (and why)

- **SQL/NoSQL injection** — no DB calls in this file.
- **SSRF / path traversal / file I/O** — no outbound HTTP or file reads.
- **Prototype pollution / mass assignment** — no request-body merging into objects.
- **Open redirect** — no `res.redirect` with user-controlled input.
- **Insecure deserialization / XXE** — no XML or `eval`/`Function` usage.

These should be re-reviewed if any of those behaviours are added later.

---

## Priority order for remediation

1. Add authentication to `/users` and minimise the fields returned. (High)
2. Enforce TLS + HSTS (ingress + `helmet`). (High)
3. Add `helmet`, `rate-limit`, body-parser limits, and a terminal error handler. (Medium)
4. Split `app.js` from `server.js`; add graceful shutdown and env-driven port. (Medium)
5. Add structured logging with secret redaction. (Medium)
6. Establish CORS policy *before* a frontend starts calling the API. (Low — but easy to get wrong under deadline pressure)

Happy to expand on any of these or produce a PR-ready diff if useful.

